```ts web/@otovo/shared/types/cloudApi.ts
import {
  Cloud$BusinessUnitType,
  Cloud$ContractPrerequisite,
  Cloud$CreditCheckStatus,
  Cloud$DiscountName,
  Cloud$DiscountType,
  Cloud$DiscountTypeFixed,
  Cloud$DiscountTypeFreeMonths,
  Cloud$DiscountTypePercentage,
  Cloud$HardwareDetailLevel,
  Cloud$HardwareType,
  Cloud$HardwareTypeBatterySystem,
  Cloud$HardwareTypePVSystem,
  Cloud$InterestStatus,
  Cloud$LoanForwardStrategy,
  Cloud$LoanStatus,
  Cloud$PackageSize,
  Cloud$PanelCellType,
  Cloud$ProductName,
  Cloud$ProjectDocumentTag,
  Cloud$ProjectPhotoTag,
  Cloud$ProjectStation,
  Cloud$SigningOption,
  Cloud$SubsidyType,
} from './cloudEnums';
import { ISODateString } from './globals';
import { Otovo$Domain, Otovo$Locale, Otovo$LocaleTerritory } from './otovoweb';
import {
  Surface$Building,
  Surface$Surface,
  Surface$Tiling,
} from './surfaceTypes';

export type Cloud$Market =
  | 'at'
  | 'be'
  | 'br'
  | 'ch'
  | 'de'
  | 'es'
  | 'fr'
  | 'gb'
  | 'it'
  | 'nl'
  | 'no'
  | 'pl'
  | 'pt'
  | 'se';
export type Cloud$Country =
  | 'at'
  | 'be'
  | 'br'
  | 'ch'
  | 'de'
  | 'es'
  | 'fr'
  | 'gb'
  | 'it'
  | 'nl'
  | 'no'
  | 'pl'
  | 'pt'
  | 'se';

/**
 * TODO: Due to inconsistenies in GQL and REST endpoints,
 * I've added Cloud$GQLCountry to make the eventual refactor easier
 *
 * NOTE: Cloud's `UK = ('gb', 'United Kingdom')` gets converted to UK in the GQL country enum, not GB
 */

export type Cloud$GQLCountry =
  | 'AT'
  | 'BR'
  | 'DE'
  | 'ES'
  | 'FR'
  | 'UK'
  | 'GLOBAL'
  | 'IT'
  | 'NO'
  | 'PL'
  | 'PT'
  | 'SE';
export type Cloud$Currency = 'NOK' | 'SEK' | 'EUR' | 'BRL' | 'PLN' | 'GBP';

export type Cloud$Subsidy = {
  amount: number;
  slug: Cloud$SubsidyType;
  amount_currency: string;
  display_name: string;
};

export type Cloud$Affiliate = {
  name: string;
  utm_sources: string[];
  logo: string;
  theming_enabled: boolean;
};

export type Cloud$Discount = {
  id: string;
  discounted_price: number;
  discount_display_name: string | null;
  name: Cloud$DiscountName;
  utm_campaigns: string[] | null;
  amount: number;
  type: 'fixed' | 'percentage' | 'free_months' | 'fixed_price';
  expiry_date: string | null;
};

type Cloud$ProductCategory = 'all' | 'pv' | 'battery' | 'ev_charger' | 'other';
type Cloud$ShoppingCartDiscountTypeAmount = 'amount';
type Cloud$ShoppingCartDiscountTypePercentage = 'percentage';
type Cloud$ShoppingCartDiscountTypeFreeMonths = 'free_months';

export type Cloud$ShoppingCartDiscountAmount = {
  type: Cloud$ShoppingCartDiscountTypeAmount;
  id: number;
  name: string;
  description: string;
  product_category: Cloud$ProductCategory;
  amount: number;
  purchase_model_restriction: Cloud$PurchaseModelCode | '';
  expiry_date: string | null;
};
type Cloud$ShoppingCartDiscountFreeMonths = {
  type: Cloud$ShoppingCartDiscountTypeFreeMonths;
  id: number;
  name: string;
  description: string;
  product_category: Cloud$ProductCategory;
  num_terms_affected: number;
  purchase_model_restriction: Cloud$PurchaseModelCode | '';
  expiry_date: string | null;
};
export type Cloud$ShoppingCartDiscountPercentage = {
  type: Cloud$ShoppingCartDiscountTypePercentage;
  id: number;
  name: string;
  amount: number;
  description: string;
  product_category: Cloud$ProductCategory;
  percent: number;
  purchase_model_restriction: Cloud$PurchaseModelCode | '';
  expiry_date: string | null;
};
export type Cloud$ShoppingCartDiscount =
  | Cloud$ShoppingCartDiscountPercentage
  | Cloud$ShoppingCartDiscountAmount
  | Cloud$ShoppingCartDiscountFreeMonths;

// ----------------------------------------------------------------
// PURCHASE MODEL CODE
// ----------------------------------------------------------------

export type Cloud$PurchaseModelCodeBuyNow = 'NOW';
export type Cloud$PurchaseModelCodeLoan = 'LOAN';
export type Cloud$PurchaseModelCodeLeasing = 'LEASING';
export type Cloud$PurchaseModelCode =
  | Cloud$PurchaseModelCodeBuyNow
  | Cloud$PurchaseModelCodeLoan
  | Cloud$PurchaseModelCodeLeasing;
export type Cloud$PurchaseModelCodeEnum = {
  BUY_NOW: Cloud$PurchaseModelCodeBuyNow;
  LOAN: Cloud$PurchaseModelCodeLoan;
  LEASING: Cloud$PurchaseModelCodeLeasing;
};

type Cloud$BuyNowEqipmentPriceItem = {
  gross_price: number;
  gross_price_currency: Cloud$Currency;
};

export type Cloud$PackageRequestBattery = {
  main_hardware_type: Cloud$HardwareTypeBatterySystem;
  battery_package_size: Cloud$PackageSize;
  with_ev_charger: boolean;
};
export type Cloud$PackageRequestPV = {
  main_hardware_type: Cloud$HardwareTypePVSystem;
  pv_product_name: Cloud$ProductName;
  pv_package_size: Cloud$PackageSize;
  with_battery: boolean;
  with_ev_charger: boolean;
};
export type Cloud$PackageRequest =
  | Cloud$PackageRequestBattery
  | Cloud$PackageRequestPV;

export type Cloud$PackageOptionBattery = Cloud$PackageRequestBattery & {
  minimum_battery_capacity: number;
};
export type Cloud$PackageOptionPV = Cloud$PackageRequestPV & {
  number_of_panels: number;
  nominal_system_power: number;
  nominal_panel_power: number;
};
export type Cloud$PackageOption =
  | Cloud$PackageOptionBattery
  | Cloud$PackageOptionPV;

type Cloud$EvChargerFinancing = {
  NOW?: Cloud$BuyNowEqipmentPriceItem;
  LOAN?: Cloud$BuyNowEqipmentPriceItem;
};

export type Cloud$PurchaseModelBuyNow = {
  ev_charger_financing: Cloud$EvChargerFinancing;
  purchase_model_code: Cloud$PurchaseModelCodeBuyNow;
  gross_price: number;
  gross_price_currency: Cloud$Currency;
  total_gross_price: number;
  total_gross_price_currency: Cloud$Currency;
  total_net_price: number;
  total_net_price_currency: Cloud$Currency;
  total_price: number;
  total_price_currency: Cloud$Currency;
  total_base_price: number;
  subsidy: Cloud$Subsidy;
  discount: Cloud$Discount | null;
  shopping_cart_discounts: Array<Cloud$ShoppingCartDiscount> | null;
  other_data: Cloud$ShoppingCartFinancingData | null;
};
export type Cloud$PurchaseModelLoan = {
  ev_charger_financing: Cloud$EvChargerFinancing;
  purchase_model_code: Cloud$PurchaseModelCodeLoan;
  gross_price: number;
  gross_price_currency: Cloud$Currency;
  loan_interest_basis_points: number;
  loan_num_terms: number;
  loan_provider_name: string;
  loan_provider_slug: string;
  monthly_loan_gross_price: number;
  monthly_loan_gross_price_currency: Cloud$Currency;
  monthly_loan_net_price: number;
  monthly_loan_net_price_currency: Cloud$Currency;
  monthly_loan_price: number;
  monthly_loan_price_currency: Cloud$Currency;
  total_gross_price: number;
  total_gross_price_currency: Cloud$Currency;
  total_net_price: number;
  total_net_price_currency: Cloud$Currency;
  total_price: number;
  total_price_currency: Cloud$Currency;
  total_base_price: number;
  subsidy: Cloud$Subsidy;
  discount: Cloud$Discount | null;
  shopping_cart_discounts: Array<Cloud$ShoppingCartDiscount> | null;
  other_data: Cloud$ShoppingCartFinancingData | null;
};
export type Cloud$PurchaseModelLeasing = {
  ev_charger_financing: Cloud$EvChargerFinancing;
  purchase_model_code: Cloud$PurchaseModelCodeLeasing;
  gross_price: number;
  gross_price_currency: Cloud$Currency;
  leasing_annual_percentage_rate: number;
  leasing_interest_basis_points: number;
  leasing_num_terms: number;
  leasing_subsidy_terms: number;
  monthly_leasing_gross_price: number;
  monthly_leasing_gross_price_currency: Cloud$Currency;
  monthly_leasing_net_price: number;
  monthly_leasing_net_price_currency: Cloud$Currency;
  monthly_leasing_price: number;
  monthly_leasing_price_currency: Cloud$Currency;
  total_gross_price: number;
  total_gross_price_currency: Cloud$Currency;
  total_net_price: number;
  total_net_price_currency: Cloud$Currency;
  total_price: number;
  total_price_currency: Cloud$Currency;
  total_base_price: number;
  subsidy: Cloud$Subsidy;
  split_leasing: boolean;
  split_leasing_num_terms: number;
  split_leasing_last_common_term: number;
  discount: Cloud$Discount | null;
  shopping_cart_discounts: Array<Cloud$ShoppingCartDiscount> | null;
  other_data: Cloud$ShoppingCartFinancingData | null;
};
export type Cloud$PurchaseModel =
  | Cloud$PurchaseModelLoan
  | Cloud$PurchaseModelBuyNow
  | Cloud$PurchaseModelLeasing;

type Cloud$ShoppingCartFinancingDataLoan = {
  purchase_model_code: Cloud$PurchaseModelCodeLoan;
  total_gross_price: number;
  total_gross_price_unmodified: number;
  discounts: Array<Cloud$ShoppingCartDiscount>;
};
type Cloud$ShoppingCartFinancingDataBuyNow = {
  purchase_model_code: Cloud$PurchaseModelCodeBuyNow;
  total_gross_price: number;
  total_gross_price_unmodified: number;
  discounts: Array<Cloud$ShoppingCartDiscount>;
};
type Cloud$ShoppingCartFinancingDataLeasing = {
  purchase_model_code: Cloud$PurchaseModelCodeLeasing;
  total_gross_price: number;
  total_gross_price_unmodified: number;
  monthly_leasing_gross_price: number;
  discounts: Array<Cloud$ShoppingCartDiscount>;
};
export type Cloud$ShoppingCartFinancingData =
  | Cloud$ShoppingCartFinancingDataLoan
  | Cloud$ShoppingCartFinancingDataBuyNow
  | Cloud$ShoppingCartFinancingDataLeasing;

export type Cloud$ShoppingCartFinancingOptionBuyNow =
  Cloud$ShoppingCartFinancingDataBuyNow & {
    total_net_price: number;
    subsidy: Cloud$Subsidy | null;
    pv_data: Cloud$ShoppingCartFinancingData | null;
    battery_data: Cloud$ShoppingCartFinancingData | null;
    ev_charger_data: Cloud$ShoppingCartFinancingData | null;
    other_data: Cloud$ShoppingCartFinancingData | null;
  };
export type Cloud$ShoppingCartFinancingOptionLoan =
  Cloud$ShoppingCartFinancingDataLoan & {
    total_net_price: number;
    subsidy: Cloud$Subsidy | null;
    pv_data: Cloud$ShoppingCartFinancingData | null;
    battery_data: Cloud$ShoppingCartFinancingData | null;
    ev_charger_data: Cloud$ShoppingCartFinancingData | null;
    other_data: Cloud$ShoppingCartFinancingData | null;
    loan_provider_slug: string;
    loan_provider_name: string;
    loan_interest_basis_points: number;
    loan_num_terms: number;
    monthly_loan_net_price: number;
    monthly_loan_gross_price: number;
    loan_start_balance: number;
    loan_total_amount_payable: number;
  };
export type Cloud$ShoppingCartFinancingOptionLeasing =
  Cloud$ShoppingCartFinancingDataLeasing & {
    total_net_price: number;
    subsidy: Cloud$Subsidy | null;
    pv_data: Cloud$ShoppingCartFinancingData | null;
    battery_data: Cloud$ShoppingCartFinancingData | null;
    ev_charger_data: Cloud$ShoppingCartFinancingData | null;
    other_data: Cloud$ShoppingCartFinancingData | null;
    leasing_annual_percentage_rate: number;
    leasing_interest_basis_points: number;
    leasing_num_terms: number;
    leasing_subsidy_terms: number;
    monthly_leasing_net_price: number;
    split_leasing: boolean;
    split_leasing_num_terms: number;
    split_leasing_last_common_term: number;
    leasing_start_balance: number;
    leasing_total_amount_payable: number;
  };
export type Cloud$ShoppingCartFinancingOption =
  | Cloud$ShoppingCartFinancingOptionBuyNow
  | Cloud$ShoppingCartFinancingOptionLoan
  | Cloud$ShoppingCartFinancingOptionLeasing;

type Cloud$UserProfile = {
  national_phone_number: string;
  phone_number: string;
  thumbnail_url: string;
  has_ssn: boolean;
};
