  data_sheet_url: string;
  is_internal: boolean;
};
export type Cloud$Inverter = {
  count: number;
  manufacturer_name: string;
  model_name: string;
  model_id: string;
  data_sheet_url: string;
  is_internal: boolean;
};
export type Cloud$Optimizers = {
  count: number;
};
export type Cloud$Battery = {
  count: number;
  manufacturer_name: string;
  model_name: string;
  display_name: string;
  data_sheet_url?: string;
  slug: string;
