};
export type Cloud$SmartMeter = {
  count: number;
  manufacturer_name: string;
  display_name: string;
  data_sheet_url?: string;
};
export type Cloud$EVCharger = {
  count: number;
  manufacturer_name: string;
  display_name: string;
  data_sheet_url?: string;
};
export type Cloud$Agent = Cloud$User;
export type Cloud$LegalContact = {
  id: number;
  username: string;
  email: string;
  first_name: string;
  last_name: string;
  profile: Cloud$UserProfile;
};
type Cloud$Customer = {
  customer_number: number;
  legal_contact: Cloud$LegalContact;
  legal_address_text_field: string | null | undefined;
  name: string;
  validated_administrative_information: boolean;
};
export type Cloud$Savings = {
  avg_kwh_price: number;
  feed_in_price: number;
  co2_savings: number;
  co2_savings_coefficient_source_url: string;
  energy_price_inflation_yearly_percent: number;
  energy_price_source_url: string;
  monthly_savings?: number;
  total_savings?: number;
  years_used_to_calculate_total_savings: number;
