  self_consumption_function_slope?: number;
};

export type Cloud$BoundingBox = [number, number, number, number];
export type Cloud$Address = {
  id: string;
  address_lines: Array<string>;
  buildings: Array<Surface$Building>;
  cadastral_unit_id: string;
  cadastral_unit_number: string;
  cadastral_address_id: string;
  county_code: string;
  county_name: string;
  country: Cloud$Country;
  latitude: number;
  leasehold_number: number | null | undefined;
  longitude: number;
  municipality_name: string;
  property_unit_number: number;
  street_address: string;
  sunrise: string;
  // date formatted string
  sunset: string;
  // date formatted string
  zip_code_code: string;
  zip_code_name: string;
  municipality_code: string;
  bounding_box?: Cloud$BoundingBox;
};

export type Cloud$Equipment = {
  panels: Cloud$Panels;
  inverters: Array<Cloud$Inverter>;
