};

export type Cloud$ShoppingCart = {
  id: string;
  financing_options: Array<Cloud$ShoppingCartFinancingOption>;
  surfaces: Array<Cloud$SpecSurface>;
  equipment: Cloud$Equipment;
  is_standalone_battery: boolean;
  num_panels: number;
  num_optimizers: number;
  nominal_system_power: number;
  minimum_nominal_system_power: number;
  energy_production_year_1: number;
  energy_production_monthly_year_1: Cloud$MonthlyEnergyProduction;
  energy_production_30_year_avg: number;
