function getFinancingOption(
  purchaseModel: Cloud$PurchaseModelCode,
  selectedPackage: Cloud$ShoppingCartPackage,
): Cloud$ShoppingCartFinancingOption | Record<string, never> {
  return (
    selectedPackage?.price.financing_options.reduce<
      Record<Cloud$PurchaseModelCode, Cloud$ShoppingCartFinancingOption>
    >(
      (prev, next) => ({ ...prev, [next.purchase_model_code]: next }),
